#include <iostream>
using namespace std;
bool ss(int a){
	int s=2;
	while(s<a){
		if(a%s==0){
			return 0;
		}
		s++;
	}
	return 1;
}
int main() {
	unsigned long long n;
	cin>>n;
	if(n<=4){
		cout<<"empty";
		return 0;
	}
	for(int i=3;i<=n;i+=2){
		if(ss(i)&&ss(i+2)&&i+2<=n){
			cout<<i<<" "<<i+2<<"\n";
		}
	}
	return 0;
}
